+    fn can_preserve_existing_live_vtabs_after_reload(
+        &self,
+        bound_visible_commit_seq: CommitSeq,
+        reloaded_schema_cookie: u32,
+    ) -> bool {
+        // Reusing the in-process live-vtab object is only safe when the reload
+        // is catching up to this connection's own latest commit and the schema
+        // cookie is unchanged. Any external writer or DDL boundary must rebuild
+        // from persisted rows.
+        reloaded_schema_cookie == *self.schema_cookie.borrow()
+            && self
+                .last_local_commit_seq
+                .borrow()
+                .is_some_and(|seq| seq == bound_visible_commit_seq)
+    }
